var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"우와...... 사방에 이터니움이 쫙 깔렸어!","JPN":"うわあ……一面エタニウムだらけだ！","ENG":"Whoa... There's Eternium everywhere!","TWN":"哇……四周全是永恆之金。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"이 일 하면서 저렇게 큰 덩어리는 처음 봐...... 이거 진짜 한 몫 단단히 잡겠는데?","JPN":"あんな大きな塊は初めてみた……こりゃあ一儲けできそうだな！","ENG":"I've never seen chunks that big even in this line of work... We could really make a fortune from this!","TWN":"在這行做這麼久，第一次見到這麼大塊的永恆之金…… 這次真的賺翻了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"으으음......","JPN":"うーん……","ENG":"Hmm...","TWN":"呃呃嗯……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"아까부터 왜 그렇게 두리번거려? 뭐 찾는 거라도 있어?","JPN":"さっきから何をそんなキョロキョロしてるんだ？　探し物でもあるか？","ENG":"Why do you keep glancing about? Looking for something?","TWN":"你在東張西望什麼？在找什麼東西嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아, 대장님! 리타 언니 못 보셨어요?","JPN":"あ、隊長！　リタお姉ちゃんを見ていませんか？","ENG":"Oh, Captain! Have you seen Rita?","TWN":"啊，隊長！您沒看到麗塔姐姐嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"금방 따라잡을 줄 알았는데 너무 멀어졌나 봐요.","JPN":"すぐ追いつくと思ったのですが、全然見えなくて。","ENG":"I thought I'd catch up to her right away, but I guess I fell behind.","TWN":"以為馬上就能追上，但好像被他甩遠了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"그 사채업자 누님이라면 한참 전에 앞질러 갔을걸.","JPN":"あの闇金業者のお姉さんはずいぶん前に進んで行ったよ。","ENG":"That loan shark lady went ahead of us already.","TWN":"那個高利貸大姐好像衝在最前面了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"우리야 고맙지. 침식체란 침식체는 죄다 해치워 주잖아.","JPN":"俺らとしては助かるよ。手当たり次第に侵食体を倒してくれるからな。","ENG":"Not that we mind. She's clearing all the C.O.s out of the way.","TWN":"多虧她，把路上的侵蝕體都給解決了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그래도 싸움을 전부 떠맡으면 언니도 힘들 텐데......","JPN":"でも全部を相手にしてたらお姉ちゃんだって疲れちゃうのに……","ENG":"But it must be exhausting for her to do all the fighting...","TWN":"但是姐姐一個人全部解決的話她會累的……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"네가 싸울 일 없으라고 그러는 거 아냐? 굉장히 걱정하는 눈치던데?","JPN":"君が戦わなくて済むようにしてるんじゃないか？　結構心配している様子だったぞ。","ENG":"She just wants to make sure you don't have to fight, I think. She seems awfully concerned about you.","TWN":"應該是為了你才掃清掉所有障礙的吧？她好像很擔心你。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"우움......","JPN":"うーん……","ENG":"Um...","TWN":"嗯……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"이봐요, 거기! 잠깐만요!","JPN":"あの、そこのあなた！　待ってください！","ENG":"Hey, you over there! Wait!","TWN":"喂，等等！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"당신 손에 들고 있는 사진기, 어디서 난 겁니까?","JPN":"その手に持っているカメラは、どこで手に入れたものですか？","ENG":"Where did you get that camera?","TWN":"你手上的那個相機是從哪來的？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"아, 이거. 바닥에 떨어져 있던데요.","JPN":"こ、これですか？　地面に落ちていましたよ。","ENG":"Oh, this? It was on the ground.","TWN":"啊，這個啊。在地上撿的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"기념사진이라도 찍으려고 했는데 작동을 안 하네.","JPN":"記念写真でも撮ろうとしたのに、作動しないっすよ。","ENG":"I thought I'd take a photo to mark the occasion, but it doesn't work.","TWN":"本來想拍個紀念照的，但是啟動不了啊。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"당장 이리 내놔요! 아티팩트면 어쩌려고요!","JPN":"今すぐ僕に渡してください！　アーティファクトだったらどうするんですか！","ENG":"Give me that, right now! It could be an Artifact!","TWN":"馬上給我！如果是人造神器怎麼辦！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"뭘 그렇게 야단을 떱니까. 그냥 잡동사니일 수도 있지.","JPN":"そんな大げさな。ただのがらくたかもしれないのに。","ENG":"What's the big deal? It looks like junk to me.","TWN":"有必要喊這麼大聲嗎。也有可能就只是個垃圾啊。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"뭐?","JPN":"は？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"아는 게 없는 당신 눈엔 죄다 쓰레기로 보이겠지! 이래서 무식한 것들은!","JPN":"何の知識もないあなたの目にはゴミ同然に映るでしょうね！　これだから無知な連中は！","ENG":"Of course it does, you dimwit! Fools like you don't know how to appreciate anything of real value!","TWN":"沒見識的廢物，眼裡看什麼都像是垃圾吧！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"뭐? 무식?","JPN":"は？　無知？","ENG":"What did you call me? Dimwit?","TWN":"什麼？廢物？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"대장한테도 그러더니 진짜 한 판 붙어 보잔 거야?","JPN":"隊長にも生意気な態度とりやがってたな、やるか！？","ENG":"I didn't like how you treated the Captain earlier, and now this? You really want to duke it out man?","TWN":"你之前對隊長也是惡言相向，你想打架嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"자, 자. 서로 진정합시다.","JPN":"まあまあ、お互い落ち着こう。","ENG":"There, there. Let's all take it down a notch.","TWN":"好了，好了。各位冷靜一下。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"윌버 씨, 잠깐 저쪽으로 가요! 그러다 총이라도 맞으면 어쩌려고요!","JPN":"ウィルバーさん、ちょっと離れましょう！　撃たれちゃいますよ！","ENG":"Mr. Wilbur, why don't you go cool off over there? You could get yourself shot!","TWN":"韋爾伯，你去那邊吧！萬一他開槍了怎麼辦！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"그깟 카메라가 뭐 대수라고 그래. 그냥 넘겨 줘.","JPN":"たかがカメラだろ。渡してやれ。","ENG":"Come on, buddy. It's just a broken camera. Just give it to the Doc.","TWN":"不就是個相機嗎，給他吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"쳇...... 못 해 먹겠네, 진짜!","JPN":"ちっ……やってられねえな、ったくよ。","ENG":"Hmpf... I've just about had it with this guy!","TWN":"切……有什麼了不起的，真是的！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"다들 구경 그만하고 이터니움이나 챙겨! 왔던 길이 닫히면 꼼짝없이 갇히는 거야!","JPN":"みんな、見物は終わりだ！　エタニウムをさっさと運べ！　道が塞がると家に帰れなくなるぞ！","ENG":"Everyone, stop watching these two and grab the Eternium! We'll be trapped in here if the path closes!","TWN":"大家都別看熱鬧了，快去拿永恆之金！若是通道關閉，我們就只能被關在這裡了！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"이러니 어릴 때 교육이 중요하다는 거예요.","JPN":"こんなんだから、幼少期からの教育が大事ってことです。","ENG":"This is why childhood education is so important.","TWN":"所以說小時候的教育很重要。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"모르면 가만히라도 있을 것이지...... 총질이나 할 줄 아는 게 어딜......","JPN":"知らないなら大人しくしてればいいのに……脳筋のくせに調子に乗って……","ENG":"Idiots like that don't know when to shut up... He's nothing but a trigger-happy goon...","TWN":"不懂的話就老老實實待著……開槍算什麼本事……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"너무 흥분하신 거 같아요. 이 유적은 윌버 씨가 평생 동안 꿈꿔 왔던 곳이라면서요.","JPN":"落ち着いてください。この遺跡はウィルバーさんの一生の夢だったんでしょう。","ENG":"I think you're getting a bit carried away. Finding this place was your lifelong dream, wasn't it?","TWN":"你好像很生氣，這個遺跡不是你一生追求的夢想嗎。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"꿈을 이뤘는데 기쁘지 않으세요?","JPN":"夢が叶ったのに嬉しくないのですか？","ENG":"Aren't you happy that you finally fulfilled your dream?","TWN":"夢想實現了，不開心嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"크흠......","JPN":"コホン……","ENG":"Ahem...","TWN":"咳咳……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"미안합니다. 추태를 부렸네요.","JPN":"すみません。見苦しいところを見せてしまいました。","ENG":"I apologize. I've made a scene.","TWN":"抱歉，是我失禮了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"살면서 저런 사람들을 한두 번 본 것도 아닌데 너무 흥분했어요.","JPN":"これまであんな輩は散々見てきたはずなのに、つい興奮しすぎました。","ENG":"It's not my first time dealing with folks like that, but I really got carried away.","TWN":"這種人以前也不是沒碰過，的確是我太激動了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"헤헤, 아티팩트에 대해 잘 설명해 주시면 용병 아저씨들도 이해해 주실 거예요.","JPN":"ヘヘッ、アーティファクトについてちゃんと説明してあげたら、傭兵のおじさんたちもわかってくれると思いますよ。","ENG":"Heh heh, I'm sure the mercenaries will understand if you explain about the Artifacts.","TWN":"嘿嘿，您好好說明一下人造神器，傭兵叔叔們也會理解的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"당신은...... 역시 돈에 미쳐 사는 속물들이랑은 다르네요.","JPN":"あなたは……やはり金にしか目がない下品な連中とは違いますね。","ENG":"You... are very different from those ignorant fools who think of nothing but money.","TWN":"你……真的跟那些只把錢當回事的庸人不同啊。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"정말 다행입니다. 아직 세상에는 옳고 그른 걸 아는 사람들이 남아 있어요.","JPN":"よかったです。まだ世の中に物事の是非をわきまえられる人が残っていて。","ENG":"That's such a relief. There are still people in the world who appreciate what's really important.","TWN":"真是萬幸。世界上還有明辨是非的人存在。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"넹? 윌버 씨는 돈 버는 게 싫으세요?","JPN":"え？　ウィルバーさんはお金を稼ぐことが嫌なんですか？","ENG":"Huh? Don't you want to make money?","TWN":"嗯？您不喜歡賺錢嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"아뇨. 뭐든 돈 얘기부터 꺼내는 사람들이 싫은 겁니다.","JPN":"いいえ。何事もすべてお金の話から始める人間が嫌なだけです。","ENG":"That's not it. I just deplore people who can't think of anything else.","TWN":"不是，我只是討厭做什麼事都先提到錢的人。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"제가 연구를 시작할 때부터 그랬죠.","JPN":"僕が研究を始めた頃もそうでした。","ENG":"It's always been like that, ever since I started my research.","TWN":"從我開始研究的時候就是如此。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"수익성은 있냐느니, 투자금은 건질 수 있겠냐느니......","JPN":"収益性はあるか、投資金はいつ返ってくるか……","ENG":"They wanted to know if it was profitable, if they could break even on their investment...","TWN":"總是問我會賺錢嗎，投入的資金能全部回收的回來嗎……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"심지어 믿었던 교수님마저 그딴 소리를 내뱉더군요.","JPN":"あろうことか、信じていた教授までそんなことを言っていました。","ENG":"Even the professor, whom I trusted so much, eventually spewed out that same garbage.","TWN":"甚至連我曾經信任的教授也說那樣的話。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"그래서...... 제 발로 대학을 박차고 나왔던 겁니다.","JPN":"だから……自分の足で大学から出て行ったのです。","ENG":"And that's why... I left the university by my own choice.","TWN":"所以……我當時才離開了大學。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아깝다...... 전 고등학교도 못 갔는데......","JPN":"もったいない……私は高校も行けてないのに……","ENG":"That's too bad... I couldn't even go to high school...","TWN":"真可惜……我連高中的沒上過……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"고등학교도요?","JPN":"高校もですか？","ENG":"Not even high school?","TWN":"高中？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"그런데 왜 그런 인간 말종들 밑에서 일하고 있는 겁니까?","JPN":"それなのに、なぜあんな連中のところで働いているんですか？","ENG":"Then why are you working for those dirt bags?","TWN":"那你為什麼在那些人渣手下做事呢？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"빚을 갚아야 하거든요.","JPN":"借金があるんです。","ENG":"I've got a debt to pay.","TWN":"我要還債。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"열심히 일해서 빚을 전부 갚고, 가족들이랑 한 집에서 사는 게 제 꿈이에요!","JPN":"一生懸命働いて借金を全部返して、家族と同じ家で暮らすのが私の夢です！","ENG":"My dream is to pay off the debt and live under one roof with my family!","TWN":"努力工作把債還清，跟家人們一起生活是我的夢想！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"그렇군요. 응원하겠습니다.","JPN":"そうでしたか。応援します。","ENG":"I see. I'll be rooting for you.","TWN":"原來如此，我支持你。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"당신처럼 선량한 사람이라면 반드시 꿈을 이룰 거예요.","JPN":"あなたみたいな善良な人なら、きっと夢を叶えるでしょう。","ENG":"I'm sure a kind-hearted person like you will achieve your dream.","TWN":"像你這樣善良人，一定會夢想成真的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"고맙습니다! 그 말을 들으니까 기운이 나는 것 같아요!","JPN":"ありがとうございます！　今の言葉でなんだか元気が出ました！","ENG":"Thanks! That really cheers me up!","TWN":"謝謝！聽你這麼說，我好像更有動力了！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그런데 윌버 씨, 그 카메라도 정말 아티팩트일 수 있어요?","JPN":"ところでウィルバーさん、そのカメラも本当にアーティファクトの可能性があるんですか？","ENG":"By the way, do you think that camera could really be an Artifact?","TWN":"但是韋爾伯，那個相機真的可能是人造神器嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"그럼요. 가능성은 충분히 있습니다.","JPN":"もちろんです。可能性は十分あります。","ENG":"Certainly. It's always possible.","TWN":"當然了，非常有可能。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"만약 아티팩트라고 해도, 어떤 현상을 일으킬지는 실험해 봐야 알겠지만요.","JPN":"もしアーティファクトだとしても、どんな現象を起こすかは実験してみないとわかりませんね。","ENG":"Although, I'll have to run a few tests to verify what it can do, if it is an Artifact.","TWN":"不過，就算是神器，也要經過試驗之後才能知道具體功能。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"가장 쉽게 확인하는 방법은 역시 피사체를 찍는 거겠죠.","JPN":"一番簡単な方法は、やはり被写体を撮ってみることでしょう。","ENG":"The easiest way to find out would be to simply take a picture.","TWN":"最簡單的方法還是拍個照測試一下。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"일반인 상대로는 위험하고......","JPN":"一般人相手だと危険だから……","ENG":"But it's too risky to do it with an ordinary person...","TWN":"不過不能拍普通人類……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"......그렇지.","JPN":"……そうだ。","ENG":"Oh, that's right.","TWN":"……是啊。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"당신이 좀 도와 주면 되겠네요.","JPN":"ちょっと手を貸してください。","ENG":"Perhaps you can help me.","TWN":"還是說你來幫我一下吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};